1	// Approximate, synthesizable FP primitive implementations for CIRCT Handshake
2	// floating-point externs.  Public module names and ports are unchanged.
3	//
4	// Implementation model: decode f32/f64 bit patterns into Q16.16 fixed point,
5	// operate in fixed point, then encode back to f32 where required.
6	
7	package circt_fp_fixed_pkg;
8	  localparam logic signed [31:0] Q_ONE = 32'sd1  <<< 16;
9	  localparam logic signed [31:0] Q4    = 32'sd4  <<< 16;
10	  localparam logic signed [31:0] Q8    = 32'sd8  <<< 16;
11	  localparam logic signed [31:0] Q9    = 32'sd9  <<< 16;
12	  localparam logic signed [31:0] Q27   = 32'sd27 <<< 16;
13	  localparam logic signed [31:0] Q3_2  = 32'sd3  <<< 15;
14	
15	  function automatic logic signed [31:0] sat32(input logic signed [63:0] x);
16	    begin
17	      sat32 = (x > 64'sh000000007fffffff) ? 32'sh7fffffff :
18	              (x < -64'sh0000000080000000) ? 32'sh80000000 : x[31:0];
19	    end
20	  endfunction
21	
22	  function automatic logic signed [31:0] f32_to_q16_16(input logic [31:0] f);
23	    logic sign; logic [7:0] exp; logic [22:0] frac; logic [23:0] mant;
24	    integer e, shift; logic signed [63:0] scaled;
25	    begin
26	      sign = f[31]; exp = f[30:23]; frac = f[22:0];
27	      if ((exp == 8'h00) && (frac == 23'h0)) begin
28	        f32_to_q16_16 = 32'sh00000000;
29	      end else if (exp == 8'hff) begin
30	        f32_to_q16_16 = sign ? 32'sh80000000 : 32'sh7fffffff;
31	      end else begin
32	        if (exp == 8'h00) begin mant = {1'b0, frac}; e = -126; end
33	        else begin mant = {1'b1, frac}; e = $signed({1'b0, exp}) - 127; end
34	        shift = e - 23 + 16;
35	        scaled = $signed({40'b0, mant});
36	        scaled = (shift >= 0) ? (scaled <<< shift) : (scaled >>> (-shift));
37	        if (sign) scaled = -scaled;
38	        f32_to_q16_16 = sat32(scaled);
39	      end
40	    end
41	  endfunction
42	
43	  function automatic logic signed [31:0] f64_to_q16_16(input logic [63:0] f);
44	    logic sign; logic [10:0] exp; logic [51:0] frac; logic [52:0] mant;
45	    integer e, shift; logic signed [63:0] scaled;
46	    begin
47	      sign = f[63]; exp = f[62:52]; frac = f[51:0];
48	      if ((exp == 11'h000) && (frac == 52'h0)) begin
49	        f64_to_q16_16 = 32'sh00000000;
50	      end else if (exp == 11'h7ff) begin
51	        f64_to_q16_16 = sign ? 32'sh80000000 : 32'sh7fffffff;
52	      end else begin
53	        if (exp == 11'h000) begin mant = {1'b0, frac}; e = -1022; end
54	        else begin mant = {1'b1, frac}; e = $signed({1'b0, exp}) - 1023; end
55	        shift = e - 52 + 16;
56	        scaled = $signed({11'b0, mant});
57	        scaled = (shift >= 0) ? (scaled <<< shift) : (scaled >>> (-shift));
58	        if (sign) scaled = -scaled;
59	        f64_to_q16_16 = sat32(scaled);
60	      end
61	    end
62	  endfunction
63	
64	  function automatic logic [31:0] q16_16_to_f32(input logic signed [31:0] q);
65	    logic sign; logic [63:0] mag, norm; logic [7:0] exp; logic [22:0] frac;
66	    integer msb, e, i, found;
67	    begin
68	      if (q == 0) begin
69	        q16_16_to_f32 = 32'h00000000;
70	      end else begin
71	        sign = q[31]; mag = sign ? $unsigned(-q) : $unsigned(q);
72	        msb = 0; found = 0;
73	        for (i = 63; i >= 0; i = i - 1) begin
74	          if ((found == 0) && mag[i]) begin msb = i; found = 1; end
75	        end
76	        if (found == 0) q16_16_to_f32 = 32'h00000000;
77	        else begin
78	          e = msb - 16;
79	          if (e > 127) q16_16_to_f32 = {sign, 8'hfe, 23'h7fffff};
80	          else if (e < -126) q16_16_to_f32 = {sign, 8'h00, 23'h000000};
81	          else begin
82	            norm = (msb >= 23) ? (mag >> (msb - 23)) : (mag << (23 - msb));
83	            exp = e + 127; frac = norm[22:0]; q16_16_to_f32 = {sign, exp, frac};
84	          end
85	        end
86	      end
87	    end
88	  endfunction
89	
90	  function automatic logic signed [31:0]
91	      q_mul(input logic signed [31:0] a, input logic signed [31:0] b);
92	    logic signed [63:0] prod;
93	    begin prod = $signed(a) * $signed(b); q_mul = sat32(prod >>> 16); end
94	  endfunction
95	
96	  function automatic logic signed [31:0]
97	      q_div(input logic signed [31:0] a, input logic signed [31:0] b);
98	    logic signed [63:0] num, quo;
99	    begin
100	      if (b == 0) q_div = a[31] ? 32'sh80000000 : 32'sh7fffffff;
101	      else begin num = $signed(a) <<< 16; quo = num / $signed(b); q_div = sat32(quo); end
102	    end
103	  endfunction
104	
105	  function automatic logic signed [31:0] q_exp_approx(input logic signed [31:0] x);
106	    logic signed [31:0] sum, term; logic signed [63:0] acc;
107	    begin
108	      if (x <= -Q8) q_exp_approx = 32'sd0;
109	      else if (x >= Q8) q_exp_approx = 32'sh7fffffff;
110	      else begin
111	        sum = Q_ONE; term = Q_ONE;
112	        term = q_mul(term, x); acc = $signed(sum) + $signed(term);        sum = sat32(acc);
113	        term = q_mul(term, x); acc = $signed(sum) + ($signed(term) / 2);  sum = sat32(acc);
114	        term = q_mul(term, x); acc = $signed(sum) + ($signed(term) / 6);  sum = sat32(acc);
115	        term = q_mul(term, x); acc = $signed(sum) + ($signed(term) / 24); sum = sat32(acc);
116	        q_exp_approx = sum;
117	      end
118	    end
119	  endfunction
120	
121	  function automatic logic signed [31:0] q_tanh_approx(input logic signed [31:0] x);
122	    logic signed [31:0] x2, num, den; logic signed [63:0] tmp;
123	    begin
124	      if (x >= Q4) q_tanh_approx = Q_ONE;
125	      else if (x <= -Q4) q_tanh_approx = -Q_ONE;
126	      else begin
127	        x2 = q_mul(x, x);
128	        tmp = $signed(Q27) + $signed(x2); num = q_mul(x, sat32(tmp));
129	        tmp = $signed(Q27) + $signed(q_mul(Q9, x2)); den = sat32(tmp);
130	        q_tanh_approx = q_div(num, den);
131	      end
132	    end
133	  endfunction
134	
135	  function automatic logic signed [31:0] q_rsqrt_approx(input logic signed [31:0] x);
136	    logic signed [31:0] y, y2, xy2, term; integer iter;
137	    begin
138	      if (x <= 0) q_rsqrt_approx = 32'sd0;
139	      else begin
140	        y = Q_ONE;
141	        for (iter = 0; iter < 3; iter = iter + 1) begin
142	          y2 = q_mul(y, y); xy2 = q_mul(x, y2);
143	          term = sat32($signed(Q3_2) - ($signed(xy2) >>> 1));
144	          y = q_mul(y, term);
145	        end
146	        q_rsqrt_approx = y;
147	      end
148	    end
149	  endfunction
150	
151	  function automatic logic signed [31:0]
152	      q_powi_approx(input logic signed [31:0] x, input logic [63:0] p);
153	    logic signed [31:0] base, res; integer i;
154	    begin
155	      base = x; res = Q_ONE;
156	      for (i = 0; i < 64; i = i + 1) begin
157	        if (p[i]) res = q_mul(res, base);
158	        base = q_mul(base, base);
159	      end
160	      q_powi_approx = res;
161	    end
162	  endfunction
