169	  function automatic logic signed [31:0] q_roundeven(input logic signed [31:0] x);
170	    logic sign; logic signed [31:0] mag, int_part, rounded;
171	    logic [15:0] frac; logic round_up;
172	    begin
173	      sign = x[31]; mag = sign ? -x : x; int_part = mag >>> 16; frac = mag[15:0];
174	      round_up = (frac > 16'h8000) || ((frac == 16'h8000) && int_part[0]);
175	      rounded = round_up ? (int_part + 1) : int_part;
176	      q_roundeven = sign ? -sat32($signed(rounded) <<< 16) : sat32($signed(rounded) <<< 16);
177	    end
178	  endfunction
179	endpackage
